function castLine(source) {
  const bytes = source.nextBytes(3);
  const coins = [bytes[0] & 1, bytes[1] & 1, bytes[2] & 1];
  const sum = coins.map((c) => c ? 3 : 2).reduce((a, b) => a + b);
  return {
    value: sum,
    isYang: sum === 7 || sum === 9,
    isChanging: sum === 6 || sum === 9
  };
}

